def convert_to_binary(num): 
  binary_num = bin(num) 
  return binary_num[2:]

def factorial(num):
    if num == 0:
        return 1
    else:
        return num * factorial(num - 1)

def is_prime(n):
    if n <= 1: 
        return False
    for i in range(2, n):
        if n % i == 0:
            return False
    return True

int product(int x, int y) { 
  int result = x * y; 
  return result; 
}

def descending_sort(list): 
    # using bubble sort 
    n = len(list) 
    for i in range(n): 
        for j in range(0, n-i-1): 
            if list[j] < list[j+1] : 
                list[j], list[j+1] = list[j+1], list[j] 

list = [7, 9, 5, 4, 6]
descending_sort(list) 
print(list)

